// claim-office.spec.ts
import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Premium calculation (quote)", () => {
    it.todo("should return premium 5 for an empty item list (processing fee only)");
    it.todo("should quote a single sword at base premium 100 (plus first-insurance surcharge and fee)");
    it.todo("should use base premiums amulet 60, staff 80, potion 40");
    it.todo("should charge 25 per component: 2 runes give base premium 50");
    it.todo("should apply the block premium 60 for exactly 3 alike components: 3 runes give base premium 60");
    it.todo("should not apply the block to 4 alike components: 4 runes give base premium 100");
    it.todo("should price 7 runes at base premium 175");
    it.todo("should not form a block from different component types: 2 runes + 1 moonstone give base premium 75");
    it.todo("should form one block per component type: 3 runes + 3 moonstones give base premium 120");
    it.todo("should add 50% of the item base premium for a cursed item");
    it.todo("should add 30% of the item base premium for enchantment level exactly 5");
    it.todo("should not add the enchantment surcharge for enchantment level 4");
    it.todo("should stack curse and enchantment surcharges on one item");
    it.todo("should apply the cursed surcharge only to the cursed item's base premium: cursed sword + plain amulet give 210 before policy modifiers and fee");
    it.todo("should apply the 20% loyalty discount for yearsWithMHPCO exactly 2");
    it.todo("should apply the 10% first-insurance surcharge to every quote");
    it.todo("should apply the 15% follow-up discount to each quote after the first");
    it.todo("should round the final premium up to whole gold (197.5 becomes 198)");
    it.todo("should quote 165 for a newcomer (0 years) with a cursed steel sword of enchantment 3");
    it.todo("should quote 160 for a 3-year customer's second quote with a cursed sword of enchantment 7");
  });

  describe("Claim payout", () => {
    it.todo("should subtract the 100 deductible from the damage amount: regular sword (enchantment 3) damaged 500 pays out 400");
    it.todo("should apply the deductible per damaged item, not per incident: sword 500 + amulet 300 pay out 600");
    it.todo("should reimburse 50% of the damage for enchantment level 9 or higher than 8 (steel sword enchantment 9), before the deductible");
    it.todo("should reimburse dragon-material items in full: dragon sword enchantment 5 gets full reimbursement");
    it.todo("should let the 50% rule win when dragon material and enchantment 8 combine: dragon sword enchantment exactly 8, damage 1000 pays out 400");
    it.todo("should treat components as having no enchantment or material: rune damaged 200 pays out 100");
    it.todo("should return remainingCap as 2x the insurance sum minus payouts: sword + amulet have insurance sum 1600 and cap 3200");
    it.todo("should keep the insurance sum unmodified by the block discount: sword + 3 runes have insurance sum 1750");
    it.todo("should sum same-type items into the insurance sum: two swords have insurance sum 2000 and cap 4000");
    it.todo("should consume the cap across successive claims: sword (cap 2000) with two claims of 1500 pays 1400 then 600");
    it.todo("should round the final payout down to whole gold (350.5 becomes 350)");
    it.todo("should apply a separate deductible per damage entry for two insured swords");
  });

  describe("Errors", () => {
    it.todo("should reject a quote containing an unknown item type (broomstick)");
    it.todo("should reject a claim damage entry whose item type is not in the policy (amulet damaged, only sword insured)");
    it.todo("should reject a claim with more damage entries of a type than items insured (two sword damages, one sword insured)");
    it.todo("should reject a claim damage entry with an unknown item type");
    it.todo("should reject a negative damage amount");
  });

  describe("CLI", () => {
    it.todo("should read a JSON scenario from stdin and write {results: [...]} to stdout with exit code 0");
    it.todo("should exit non-zero with the error on stderr and no results on stdout for an invalid scenario");
  });
});
